INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Finde einen Fremden, der \"Ja, ich will!\" sagt, und nimm es auf.","type":"aufgabe"},"en":{"text":"Start a conga line — everyone must join.","type":"aufgabe"},"es":{"text":"Pon tu mejor cara de flirteo y mantela 10 segundos.","type":"aufgabe"},"fr":{"text":"Fais ton meilleur visage de drague pendant 10 secondes.","type":"aufgabe"},"it":{"text":"Fai la tua migliore faccia da flirt per 10 secondi.","type":"aufgabe"},"nl":{"text":"Maak je beste flirtgezicht en houd het 10 seconden.","type":"aufgabe"},"pl":{"text":"Znajdź nieznajomego, który powie „Tak, chcę!\" i nagraj to.","type":"aufgabe"},"pt":{"text":"Faz a tua melhor cara de flirt e mantem durante 10 segundos.","type":"aufgabe"},"tr":{"text":"\"Evet, kabul ediyorum!\" diyen bir yabancı bul ve kaydet.","type":"aufgabe"},"ar":{"text":"ابحث عن شخص غريب يقول \"نعم، أقبل!\" وصوّره.","type":"aufgabe"}}', 'medium', 'jga', true);
