INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Was ist dein Lieblingsfilm, den du nie oeffentlich zugeben würdest?","type":"frage"},"en":{"text":"Challenge someone to a dance battle!","type":"aufgabe"},"es":{"text":"Cuenta que fue lo primero que hiciste al despertar hoy.","type":"aufgabe"},"fr":{"text":"Raconte ce que tu as fait en premier en te reveillant.","type":"aufgabe"},"it":{"text":"Racconta cosa hai fatto appena sveglio stamattina.","type":"aufgabe"},"pl":{"text":"Jaki jest twój ulubiony film, do którego nigdy publicznie byś się nie przyznał/a?","type":"frage"},"tr":{"text":"Asla herkesin önünde itiraf edemeyeceğin en sevdiğin film ne?","type":"frage"},"ar":{"text":"ما فيلمك المفضل الذي لن تعترف به علناً أبداً؟","type":"frage"}}', 'medium', 'erwachsene', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Beiß dir auf die Lippe und schau 5 Sekunden der Person gegenüber in die Augen.","type":"aufgabe"},"en":{"text":"What was the funniest party fail?","type":"frage"},"es":{"text":"Cual fue el mejor consejo que te dieron?","type":"frage"},"fr":{"text":"Quel est le meilleur conseil qu\\","type":"frage"},"it":{"text":"Qual e il miglior consiglio che hai ricevuto?","type":"frage"},"pl":{"text":"Przygryzaj wargę i patrz 5 sekund w oczy osobie naprzeciwko.","type":"aufgabe"},"tr":{"text":"Dudağını ısır ve karşındakinin gözlerine 5 saniye bak.","type":"aufgabe"},"ar":{"text":"عضّ شفتك وانظر 5 ثوانٍ في عيني الشخص المقابل.","type":"aufgabe"}}', 'medium', 'erwachsene', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Hast du schon mal jemanden geghosted? Warum?","type":"frage"},"en":{"text":"Cheers with everyone — one by one!","type":"aufgabe"},"es":{"text":"Presentate como si fueras un personaje de pelicula.","type":"aufgabe"},"fr":{"text":"Presente-toi comme un personnage de film.","type":"aufgabe"},"it":{"text":"Presentati come un personaggio di un film.","type":"aufgabe"},"pl":{"text":"Czy kiedyś kogoś zghostowałeś/aś? Dlaczego?","type":"frage"},"tr":{"text":"Hiç birini ghostladın mı? Neden?","type":"frage"},"ar":{"text":"هل سبق وتجاهلت أحداً فجأة؟ لماذا؟","type":"frage"}}', 'medium', 'erwachsene', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Zeige das letzte Bild, das du in deiner Galerie gespeichert hast.","type":"aufgabe"},"en":{"text":"Who is the party planner in the group?","type":"frage"},"es":{"text":"Que te hace realmente feliz?","type":"frage"},"fr":{"text":"Qu\\","type":"frage"},"it":{"text":"Cosa ti rende veramente felice?","type":"frage"},"pl":{"text":"Pokaż ostatnie zdjęcie zapisane w galerii.","type":"aufgabe"},"tr":{"text":"Galerideki son kaydettiğin fotoğrafı göster.","type":"aufgabe"},"ar":{"text":"أرِ آخر صورة حفظتها في المعرض.","type":"aufgabe"}}', 'medium', 'erwachsene', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Was ist das Romantischste, das je jemand fürdich getan hat?","type":"frage"},"en":{"text":"Announce like a DJ in the club!","type":"aufgabe"},"es":{"text":"Nombra tres cosas que tu y la persona de al lado tengan en comun.","type":"aufgabe"},"fr":{"text":"Cite 3 choses en commun avec la personne a cote.","type":"aufgabe"},"it":{"text":"Nomina 3 cose che tu e la persona accanto avete in comune.","type":"aufgabe"},"pl":{"text":"Jaka jest najbardziej romantyczna rzecz, jaką ktoś dla ciebie zrobił?","type":"frage"},"tr":{"text":"Birinin senin için yaptığı en romantik şey neydi?","type":"frage"},"ar":{"text":"ما أكثر شيء رومانسي فعله أحد من أجلك؟","type":"frage"}}', 'medium', 'erwachsene', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Schreibe blind eine freche Nachricht und schicke sie an den letzten Kontakt.","type":"aufgabe"},"en":{"text":"What must never be missing at a party?","type":"frage"},"es":{"text":"Si tuvieras una maquina del tiempo, a donde irias?","type":"frage"},"fr":{"text":"Si tu avais une machine a remonter le temps, ou irais-tu?","type":"frage"},"it":{"text":"Se avessi una macchina del tempo, dove andresti?","type":"frage"},"pl":{"text":"Napisz na ślepo niegrzeczną wiadomość i wyślij do ostatniego kontaktu.","type":"aufgabe"},"tr":{"text":"Gözleri kapalı yaramaz bir mesaj yaz ve son kişiye gönder.","type":"aufgabe"},"ar":{"text":"اكتب رسالة جريئة بلا نظر وأرسلها لآخر جهة اتصال.","type":"aufgabe"}}', 'medium', 'erwachsene', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Wer hier ist am ehesten der Heartbreaker-Typ?","type":"frage"},"en":{"text":"Which party rule do you like breaking best?","type":"frage"},"es":{"text":"Cuenta tu mejor experiencia con un desconocido.","type":"aufgabe"},"fr":{"text":"Raconte ta meilleure experience avec un inconnu.","type":"aufgabe"},"it":{"text":"Racconta la tua migliore esperienza con uno sconosciuto.","type":"aufgabe"},"pl":{"text":"Kto tutaj jest najbardziej typem łamacza serc?","type":"frage"},"tr":{"text":"Burada en çok kalp kıran tipi kim?","type":"frage"},"ar":{"text":"مَن هنا هو الأكثر من نوع كاسر القلوب؟","type":"frage"}}', 'medium', 'erwachsene', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Mach 5 Liegestütze und stoehn dabei dramatisch.","type":"aufgabe"},"en":{"text":"Tell the funniest story about the bride/groom.","type":"frage"},"pl":{"text":"Zrób 5 pompek i dramatycznie przy tym jęcz.","type":"aufgabe"},"tr":{"text":"5 şınav çek ve dramatik bir şekilde inle.","type":"aufgabe"},"ar":{"text":"قم بـ 5 ضغطات وتأوّه بشكل درامي.","type":"aufgabe"}}', 'medium', 'erwachsene', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Was würdest du tun, wenn dein Ex gerade reinkaeme?","type":"frage"},"en":{"text":"Call a random person and congratulate them on the wedding.","type":"aufgabe"},"pl":{"text":"Co byś zrobił/a, gdyby twój ex właśnie wszedł?","type":"frage"},"tr":{"text":"Eski sevgilin şu an içeri girse ne yapardın?","type":"frage"},"ar":{"text":"ماذا ستفعل لو دخل حبيبك/تك السابق/ة الآن؟","type":"frage"}}', 'medium', 'erwachsene', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Setze dich fürdie nächste Runde auf den Schoss der Person links neben dir.","type":"aufgabe"},"en":{"text":"What do you think the couple will be doing in 10 years?","type":"frage"},"pl":{"text":"Na następną rundę usiądź na kolanach osoby po lewej.","type":"aufgabe"},"tr":{"text":"Sonraki tur solundaki kişinin kucağına otur.","type":"aufgabe"},"ar":{"text":"اجلس في الجولة القادمة على حضن الشخص على يسارك.","type":"aufgabe"}}', 'medium', 'erwachsene', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Was ist die frecchste Nachricht, die du je erhalten hast?","type":"frage"},"en":{"text":"Send the bride/groom an embarrassing message.","type":"aufgabe"},"pl":{"text":"Jaka jest najbezczelniejsza wiadomość, jaką kiedykolwiek otrzymałeś/aś?","type":"frage"},"tr":{"text":"Aldığın en küstah mesaj neydi?","type":"frage"},"ar":{"text":"ما أوقح رسالة تلقيتها على الإطلاق؟","type":"frage"}}', 'medium', 'erwachsene', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Was ist dein guilty pleasure?","type":"frage"},"en":{"text":"What was your first impression of the partner?","type":"frage"},"pl":{"text":"Jaka jest twoja guilty pleasure?","type":"frage"},"tr":{"text":"Suçlu zevkin ne?","type":"frage"},"ar":{"text":"ما مُتعتك المذنبة؟","type":"frage"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Wenn du eine Superkraft haettest, welche waere es?","type":"frage"},"en":{"text":"Learn a wedding dance move and perform it.","type":"aufgabe"},"pl":{"text":"Gdybyś miał/a supermoc, jaka by to była?","type":"frage"},"tr":{"text":"Bir süper gücün olsa ne olurdu?","type":"frage"},"ar":{"text":"لو كانت لديك قوة خارقة، ماذا ستكون؟","type":"frage"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Was wolltest du als Kind werden?","type":"frage"},"en":{"text":"Who cried the most when the wedding was announced?","type":"frage"},"pl":{"text":"Kim chciałeś/aś zostać w dzieciństwie?","type":"frage"},"tr":{"text":"Çocukken ne olmak istiyordun?","type":"frage"},"ar":{"text":"ماذا كنت تريد أن تصبح عندما كنت طفلاً؟","type":"frage"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Nenne eine Sache auf deiner Bucket List.","type":"frage"},"en":{"text":"Take a photo that looks like a wedding shoot.","type":"aufgabe"},"pl":{"text":"Wymień jedną rzecz ze swojej listy marzeń.","type":"frage"},"tr":{"text":"Yapılacaklar listenden bir şey söyle.","type":"frage"},"ar":{"text":"اذكر شيئاً واحداً من قائمة أمنياتك.","type":"frage"}}', 'medium', 'eisbrecher', true);
