INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Erzähle etwas, das niemand hier überdich wissen dürfte.","type":"aufgabe"},"en":{"text":"Give a mini wedding speech.","type":"aufgabe"},"pl":{"text":"Opowiedz coś, czego nikt tutaj nie powinien o tobie wiedzieć.","type":"aufgabe"},"tr":{"text":"Burada kimsenin bilmemesi gereken bir şey anlat.","type":"aufgabe"},"ar":{"text":"احكِ شيئاً لا يجب أن يعرفه أحد هنا عنك.","type":"aufgabe"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Was ist dein Lieblingsgericht und warum?","type":"frage"},"en":{"text":"Tell the most embarrassing shared memory.","type":"frage"},"pl":{"text":"Jakie jest twoje ulubione danie i dlaczego?","type":"frage"},"tr":{"text":"En sevdiğin yemek ne ve neden?","type":"frage"},"ar":{"text":"ما طبقك المفضل ولماذا؟","type":"frage"}}', 'medium', 'eisbrecher', true);
