INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Beschreibe dich selbst in drei Worten.","type":"aufgabe"},"en":{"text":"Record a 15-second congratulations video.","type":"aufgabe"},"pl":{"text":"Opisz siebie trzema słowami.","type":"aufgabe"},"tr":{"text":"Kendini üç kelimeyle anlat.","type":"aufgabe"},"ar":{"text":"صِف نفسك بثلاث كلمات.","type":"aufgabe"}}', 'medium', 'eisbrecher', true);
