INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Sage jedem in der Runde etwas Nettes.","type":"aufgabe"},"en":{"text":"Find a stranger who says \"I do!\" and record it.","type":"aufgabe"},"pl":{"text":"Powiedz każdemu w grupie coś miłego.","type":"aufgabe"},"tr":{"text":"Gruptaki herkese güzel bir şey söyle.","type":"aufgabe"},"ar":{"text":"قل شيئاً لطيفاً لكل شخص في المجموعة.","type":"aufgabe"}}', 'medium', 'eisbrecher', true);
