INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Wenn du ein Tier waerst, welches waerst du und warum?","type":"frage"},"en":{"text":"How did the bride/groom tell the proposal story?","type":"frage"},"pl":{"text":"Gdybyś był/a zwierzęciem, jakim byś był/a i dlaczego?","type":"frage"},"tr":{"text":"Bir hayvan olsan hangisi olurdun ve neden?","type":"frage"},"ar":{"text":"لو كنت حيواناً، أي حيوان ستكون ولماذا؟","type":"frage"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Zeige der Gruppe das letzte Meme, das du verschickt hast.","type":"aufgabe"},"en":{"text":"Write a marriage prophecy on a napkin.","type":"aufgabe"},"pl":{"text":"Pokaż grupie ostatniego mema, którego wysłałeś/aś.","type":"aufgabe"},"tr":{"text":"Gruba gönderdiğin son meme\\","type":"aufgabe"},"ar":{"text":"أرِ المجموعة آخر ميم أرسلته.","type":"aufgabe"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Was ist dein Lieblingszitat oder Motto?","type":"frage"},"en":{"text":"What do you wish for the couple\\","type":"frage"},"pl":{"text":"Jaki jest twój ulubiony cytat lub motto?","type":"frage"},"tr":{"text":"En sevdiğin söz veya motto ne?","type":"frage"},"ar":{"text":"ما اقتباسك أو شعارك المفضل؟","type":"frage"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Mach ein Kompliment fürdie Person, die du am wenigsten kennst.","type":"aufgabe"},"en":{"text":"Collect 5 signatures from strangers in 2 minutes.","type":"aufgabe"},"pl":{"text":"Powiedz komplement osobie, którą znasz najmniej.","type":"aufgabe"},"tr":{"text":"En az tanıdığın kişiye iltifat et.","type":"aufgabe"},"ar":{"text":"قل مجاملة للشخص الذي تعرفه أقل.","type":"aufgabe"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Was ist die beste Reise, die du je gemacht hast?","type":"frage"},"en":{"text":"What was the funniest fail of the bride/groom?","type":"frage"},"pl":{"text":"Jaka jest najlepsza podróż, jaką kiedykolwiek odbyłeś/aś?","type":"frage"},"tr":{"text":"Yaptığın en iyi seyahat hangisiydi?","type":"frage"},"ar":{"text":"ما أفضل رحلة قمت بها على الإطلاق؟","type":"frage"}}', 'medium', 'eisbrecher', true);
