INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Welche Faehigkeit würdest du gerne lernen?","type":"frage"},"en":{"text":"What did the bride/groom say when you heard about the engagement?","type":"frage"},"pl":{"text":"Jakiej umiejętności chciałbyś/chciałabyś się nauczyć?","type":"frage"},"tr":{"text":"Hangi beceriyi öğrenmek isterdin?","type":"frage"},"ar":{"text":"أي مهارة تودّ تعلّمها؟","type":"frage"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Gib der Person gegenüber einen neuen Spitznamen fürden Abend.","type":"aufgabe"},"en":{"text":"Take a photo with a stranger labeled \"Wedding Guest\".","type":"aufgabe"},"pl":{"text":"Daj osobie naprzeciwko nowe przezwisko na cały wieczór.","type":"aufgabe"},"tr":{"text":"Karşındaki kişiye gece için yeni bir lakap ver.","type":"aufgabe"},"ar":{"text":"أعطِ الشخص المقابل لقباً جديداً لهذا المساء.","type":"aufgabe"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Was ist dein Lieblingslied gerade und warum?","type":"frage"},"en":{"text":"Who should definitely NOT give a speech at the wedding? Why?","type":"frage"},"pl":{"text":"Jaka jest twoja ulubiona piosenka teraz i dlaczego?","type":"frage"},"tr":{"text":"Şu an en sevdiğin şarkı ne ve neden?","type":"frage"},"ar":{"text":"ما أغنيتك المفضلة حالياً ولماذا؟","type":"frage"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Erzähle, was du heute als Erstes nach dem Aufwachen gemacht hast.","type":"aufgabe"},"en":{"text":"Ask three people for marriage tips and write them down.","type":"aufgabe"},"pl":{"text":"Opowiedz, co zrobiłeś/aś dziś rano jako pierwsze po przebudzeniu.","type":"aufgabe"},"tr":{"text":"Bugün uyandıktan sonra ilk ne yaptığını anlat.","type":"aufgabe"},"ar":{"text":"احكِ عن أول شيء فعلته اليوم بعد الاستيقاظ.","type":"aufgabe"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Was war der beste Ratschlag, den du je bekommen hast?","type":"frage"},"en":{"text":"What kind of teenager was the bride/groom?","type":"frage"},"pl":{"text":"Jaka była najlepsza rada, jaką kiedykolwiek dostałeś/aś?","type":"frage"},"tr":{"text":"Aldığın en iyi tavsiye neydi?","type":"frage"},"ar":{"text":"ما أفضل نصيحة تلقيتها على الإطلاق؟","type":"frage"}}', 'medium', 'eisbrecher', true);
