INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Was macht dich wirklich glücklich?","type":"frage"},"en":{"text":"Name 3 things the bride/groom cannot do!","type":"frage"},"pl":{"text":"Co naprawdę czyni cię szczęśliwym/ą?","type":"frage"},"tr":{"text":"Seni gerçekten mutlu eden ne?","type":"frage"},"ar":{"text":"ما الذي يجعلك سعيداً حقاً؟","type":"frage"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Nenne drei Dinge, die du und die Person neben dir gemeinsam habt.","type":"aufgabe"},"en":{"text":"Take a pic where everyone poses like a married couple!","type":"aufgabe"},"pl":{"text":"Wymień trzy rzeczy, które łączą ciebie i osobę obok.","type":"aufgabe"},"tr":{"text":"Yanındaki kişiyle ortak üç şey say.","type":"aufgabe"},"ar":{"text":"اذكر ثلاثة أشياء مشتركة بينك وبين الشخص بجانبك.","type":"aufgabe"}}', 'medium', 'eisbrecher', true);
