INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Was kannst du besser als die meisten anderen?","type":"frage"},"en":{"text":"Do a mini meditation — everyone closes their eyes for 15 seconds.","type":"aufgabe"},"pl":{"text":"Co robisz lepiej niż większość ludzi?","type":"frage"},"tr":{"text":"Çoğu insandan daha iyi yaptığın şey ne?","type":"frage"},"ar":{"text":"ما الذي تفعله أفضل من معظم الناس؟","type":"frage"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Nenne drei Dinge, die dich und deinen Nachbarn verbinden.","type":"aufgabe"},"pl":{"text":"Wymień trzy rzeczy, które łączą ciebie i sąsiada.","type":"aufgabe"},"tr":{"text":"Seni ve komşunu birleştiren üç şeyi say.","type":"aufgabe"},"ar":{"text":"اذكر ثلاثة أشياء تجمعك بجارك.","type":"aufgabe"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Was würdest du tun, wenn du wuesstest, dass du nicht scheitern kannst?","type":"frage"},"pl":{"text":"Co byś zrobił/a, gdybyś wiedział/a, że nie możesz ponieść porażki?","type":"frage"},"tr":{"text":"Başarısız olamayacağını bilsen ne yapardın?","type":"frage"},"ar":{"text":"ماذا ستفعل لو عرفت أنك لن تفشل؟","type":"frage"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Erzähle eine Geschichte in genau 3 Saetzen.","type":"aufgabe"},"pl":{"text":"Opowiedz historię w dokładnie 3 zdaniach.","type":"aufgabe"},"tr":{"text":"Tam 3 cümlede bir hikaye anlat.","type":"aufgabe"},"ar":{"text":"احكِ قصة في 3 جمل بالضبط.","type":"aufgabe"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Was ist das Schoenste, das jemand je zu dir gesagt hat?","type":"frage"},"pl":{"text":"Jaka jest najpiękniejsza rzecz, jaką ktoś ci kiedyś powiedział?","type":"frage"},"tr":{"text":"Birinin sana söylediği en güzel şey neydi?","type":"frage"},"ar":{"text":"ما أجمل شيء قاله لك أحد على الإطلاق؟","type":"frage"}}', 'medium', 'eisbrecher', true);
INSERT INTO game_content (game_id, content_type, content, difficulty, category, is_active) VALUES ('bottlespin', 'bottle_card', '{"de":{"text":"Mach eine Mini-Meditation — alle schließen die Augen für15 Sekunden.","type":"aufgabe"},"pl":{"text":"Zrób mini-medytację — wszyscy zamykają oczy na 15 sekund.","type":"aufgabe"},"tr":{"text":"Mini meditasyon yap — herkes 15 saniye gözlerini kapatsın.","type":"aufgabe"},"ar":{"text":"قم بتأمل قصير — الكل يغمض عينيه 15 ثانية.","type":"aufgabe"}}', 'medium', 'eisbrecher', true);
